import type { Metadata, Viewport } from "next";
import { JetBrains_Mono, Source_Serif_4 } from "next/font/google";
import "./globals.css";
import SiteHeader from "@/components/shell/SiteHeader";
import SiteFooter from "@/components/shell/SiteFooter";
import ThemeInit from "@/components/shell/ThemeInit";
import MobileDrawer from "@/components/shell/MobileDrawer";
import { NavToggleProvider } from "@/components/shell/useNavToggle";
import identity from "@/content/about/identity";

const SITE_URL = process.env.SITE_URL ?? "https://personalwebsite-beta-nine.vercel.app";

const fontMono = JetBrains_Mono({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-mono",
});

const fontSerif = Source_Serif_4({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-serif",
});

export const metadata: Metadata = {
  metadataBase: new URL(SITE_URL),
  title: { default: identity.name, template: `%s — ${identity.name}` },
  description: "Operator. Writer. Founder of Hivemind.",
  openGraph: {
    type: "website",
    siteName: identity.name,
    url: SITE_URL,
  },
  twitter: { card: "summary_large_image" },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  viewportFit: "cover",
  interactiveWidget: "resizes-content",
};

export default function RootLayout({ children }: Readonly<{ children: React.ReactNode }>) {
  return (
    <html lang="en" suppressHydrationWarning className={`${fontMono.variable} ${fontSerif.variable}`}>
      <head>
        <ThemeInit />
      </head>
      <body>
        <NavToggleProvider>
          <SiteHeader />
          <MobileDrawer />
          <main id="main">{children}</main>
          <SiteFooter />
        </NavToggleProvider>
      </body>
    </html>
  );
}

